// ============ AUTO-FILL FUNCTION ============
function getFullRoster(teamId) {
  if (COMPLETE_ROSTERS[teamId]) return COMPLETE_ROSTERS[teamId];
  // Fallback: use the original ROSTERS data or generate from starters string
  const t = TEAMS.find(x => x.id === teamId);
  if (!t) return { formation: "4-3-3", starters: [], subs: [] };

  const formation = FORMATIONS[teamId] || "4-3-3";
  if (ROSTERS[teamId]) return { formation, ...ROSTERS[teamId] };

  const names = (t.starters || '').split('/');
  const starters = names.map((n, i) => ({
    pos: ["GK","DF","DF","DF","DF","MF","MF","MF","FW","FW","FW"][i] || "MF",
    name: n.trim(),
    club: "—",
    num: i + 1
  }));
  return { formation, starters, subs: [] };
}

function getStarForTeam(teamId) {
  return TEAM_STARS[teamId] || null;
}

function getPlayerImage(name) {
  return PLAYER_IMAGES[name] || null;
}

function getTeamColors(teamId) {
  return TEAM_COLORS[teamId] || ["#1a1a2e","#e94560"];
}

function getFormation(teamId) {
  return FORMATIONS[teamId] || "4-3-3";
}

